            let b1 = UInt32(bytes[i-3])
            let b2 = UInt32(bytes[i-2])
            let b3 = UInt32(bytes[i-1])
            let val = (b0 << 24) | (b1 << 16) | (b2 << 8) | b3
            w.append(val)
        }
        self.words = w.trimmed()
    }

    init(hex: String) {
        let d = Hex.decode(hex) ?? Data()
        self.init(d)
    }

    static func < (lhs: BigInt, rhs: BigInt) -> Bool {
        if lhs.words.count != rhs.words.count { return lhs.words.count < rhs.words.count }
        for i in stride(from: lhs.words.count - 1, through: 0, by: -1) {
            if lhs.words[i] != rhs.words[i] { return lhs.words[i] < rhs.words[i] }
        }
        return false
    }

    static func == (lhs: BigInt, rhs: BigInt) -> Bool {
        lhs.words == rhs.words
    }

    var isZero: Bool { words.isEmpty }
    var isOdd: Bool { !words.isEmpty && (words[0] & 1) == 1 }
    var isEven: Bool { !isOdd }

    func serialize() -> Data {
        if words.isEmpty { return Data() }
        var out = Data()
        out.reserveCapacity(words.count * 4)
        for w in words.reversed() {
            out.append(UInt8((w >> 24) & 0xff))
            out.append(UInt8((w >> 16) & 0xff))
            out.append(UInt8((w >> 8) & 0xff))
            out.append(UInt8(w & 0xff))
        }
        return out.trimmedLeadingZeros()
    }

    static func + (lhs: BigInt, rhs: BigInt) -> BigInt {
        let maxCount = max(lhs.words.count, rhs.words.count)
        var out = [UInt32](repeating: 0, count: maxCount + 1)
        var carry: UInt64 = 0
        for i in 0..<maxCount {
            let a = i < lhs.words.count ? UInt64(lhs.words[i]) : 0
            let b = i < rhs.words.count ? UInt64(rhs.words[i]) : 0
            let sum = a + b + carry
            out[i] = UInt32(sum & 0xffffffff)
            carry = sum >> 32
        }
        out[maxCount] = UInt32(carry)
        return BigInt(words: out.trimmed())
    }

    static func - (lhs: BigInt, rhs: BigInt) -> BigInt {
        // assume lhs >= rhs
        var out = lhs.words
        var borrow: Int64 = 0
        for i in 0..<out.count {
            let a = Int64(out[i])
            let b = i < rhs.words.count ? Int64(rhs.words[i]) : 0
            var v = a - b - borrow
            if v < 0 {
                v += Int64(1) << 32
                borrow = 1
            } else {
