        if words.isEmpty { return 0 }
        let last = words.last!
        return (words.count - 1) * 32 + (32 - last.leadingZeroBitCount)
    }

    static func >= (lhs: BigInt, rhs: BigInt) -> Bool { !(lhs < rhs) }
    static func > (lhs: BigInt, rhs: BigInt) -> Bool { rhs < lhs }

    func modInverse(_ m: BigInt) -> BigInt? {
        // Extended Euclid for inverse modulo m (m assumed prime in our usage)
        if m.isZero { return nil }
        var a = self.mod(m)
        if a.isZero { return nil }
        var t = BigInt(0)
        var newT = BigInt(1)
        var r = m
        var newR = a

        while !newR.isZero {
            let q = r / newR
            (t, newT) = (newT, t - q * newT)
            (r, newR) = (newR, r - q * newR)
        }
        if r != BigInt(1) { return nil }
        if t < BigInt(0) { return (t + m).mod(m) }
        return t.mod(m)
    }

    static func / (lhs: BigInt, rhs: BigInt) -> BigInt {
