        if lhs < rhs { return BigInt(0) }
        var quotient = BigInt(0)
        var remainder = lhs
        var denom = rhs
        var shift = remainder.bitWidth - denom.bitWidth
        denom = denom << shift
        var q = BigInt(1) << shift
        while shift >= 0 {
            if remainder >= denom {
                remainder = remainder - denom
                quotient = quotient + q
            }
            denom = denom >> 1
            q = q >> 1
            shift -= 1
        }
        return quotient
    }

    private init(words: [UInt32]) {
        self.words = words.trimmed()
    }
}

private extension Array where Element == UInt32 {
    func trimmed() -> [UInt32] {
        var a = self
        while let last = a.last, last == 0 { a.removeLast() }
        return a
    }
}

// MARK: - Keychain

final class KeychainStore {
    static let shared = KeychainStore()
    private init() {}

    private let service = "com.example.wallet.mvp"
    private let account = "eth_private_key_v1"

    func savePrivateKey(_ key: Data) throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(query as CFDictionary)

        let add: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        let status = SecItemAdd(add as CFDictionary, nil)
        guard status == errSecSuccess else { throw NSError(domain: "Keychain", code: Int(status)) }
    }

    func loadPrivateKey() -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess else { return nil }
        return item as? Data
    }

    func deletePrivateKey() {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Ethereum

final class EthereumWallet {
    static func address(fromUncompressedPublicKey pub: Data) -> String? {
        guard pub.count == 65, pub.first == 0x04 else { return nil }
        let xy = pub.dropFirst()
        let hash = Keccak256.hash(Data(xy))
        let addr = hash.suffix(20)
        return Hex.encode(addr, prefix: true)
    }

    static func signTransaction(_ tx: EthereumTransaction, privateKey: Data) -> Data? {
        let toField: Data = tx.to.count == 0 ? Data() : tx.to
        let rlpUnsigned: [Any] = [
            tx.nonce,
            tx.gasPrice,
            tx.gasLimit,
            toField,
            tx.value,
            tx.data,
            tx.chainId,
            0,
            0
        ]
        let encodedUnsigned = RLP.encode(rlpUnsigned)
        let hash = Keccak256.hash(encodedUnsigned)
        guard let sig = Secp256k1.sign(hash32: hash, privateKey: privateKey, chainId: tx.chainId) else { return nil }

        let vAsUInt64 = UInt64(sig.v)
        let rAsUInt64: Any = sig.r.trimmedLeadingZeros()
        let sAsUInt64: Any = sig.s.trimmedLeadingZeros()

        let rlpSigned: [Any] = [
            tx.nonce,
            tx.gasPrice,
            tx.gasLimit,
            toField,
            tx.value,
            tx.data,
            vAsUInt64,
            rAsUInt64,
            sAsUInt64
        ]
        return RLP.encode(rlpSigned)
    }
}

// MARK: - JSON-RPC

final class EthereumRPC {
    let url: URL
    init(url: URL) { self.url = url }

    struct RPCError: Error { let message: String }

    private func call<T: Decodable>(_ method: String, _ params: [Any], result: T.Type) async throws -> T {
        var req = URLRequest(url: url)
        req.httpMethod = "POST"
        req.setValue("application/json", forHTTPHeaderField: "Content-Type")
        let body: [String: Any] = [
            "jsonrpc": "2.0",
            "id": 1,
            "method": method,
            "params": params
        ]
        req.httpBody = try JSONSerialization.data(withJSONObject: body, options: [])

        let (data, resp) = try await URLSession.shared.data(for: req)
        guard let http = resp as? HTTPURLResponse, (200..<300).contains(http.statusCode) else {
            throw RPCError(message: "HTTP error")
        }

        struct Envelope<R: Decodable>: Decodable {
            let jsonrpc: String?
            let id: Int?
            let result: R?
            let error: RPCErrorObj?
            struct RPCErrorObj: Decodable { let code: Int?; let message: String? }
        }

        let env = try JSONDecoder().decode(Envelope<T>.self, from: data)
        if let e = env.error {
            throw RPCError(message: e.message ?? "RPC error")
        }
        guard let r = env.result else { throw RPCError(message: "Missing result") }
        return r
    }

    func getTransactionCount(address: String, tag: String = "latest") async throws -> UInt64 {
        let res: String = try await call("eth_getTransactionCount", [address, tag], result: String.self)
        return UInt64(res.strip0x(), radix: 16) ?? 0
    }

    func gasPrice() async throws -> UInt64 {
        let res: String = try await call("eth_gasPrice", [], result: String.self)
        return UInt64(res.strip0x(), radix: 16) ?? 0
    }

    func sendRawTransaction(_ rawTx: Data) async throws -> String {
        let hex = Hex.encode(rawTx, prefix: true)
        let res: String = try await call("eth_sendRawTransaction", [hex], result: String.self)
        return res
    }

    func getBalance(address: String, tag: String = "latest") async throws -> String {
        let res: String = try await call("eth_getBalance", [address, tag], result: String.self)
        return res
    }
}

private extension String {
    func strip0x() -> String {
        if lowercased().hasPrefix("0x") { return String(dropFirst(2)) }
        return self
    }
}

// MARK: - UI

final class WalletViewController: UIViewController {
    private let rpcURLField = UITextField()
    private let addressLabel = UILabel()
    private let pubKeyLabel = UILabel()
    private let balanceLabel = UILabel()
    private let statusLabel = UILabel()

    private let generateButton = UIButton(type: .system)
    private let deleteButton = UIButton(type: .system)
    private let refreshButton = UIButton(type: .system)

    private let toField = UITextField()
    private let amountField = UITextField()
    private let sendButton = UIButton(type: .system)

    private var cachedInfo: WalletKeyInfo?

    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Crypto Wallet MVP"
        view.backgroundColor = .systemBackground
        setupUI()
        loadOrShow()
    }

    private func setupUI() {
        rpcURLField.placeholder = "RPC URL (e.g. https://mainnet.infura.io/v3/KEY)"
        rpcURLField.borderStyle = .roundedRect
        rpcURLField.autocapitalizationType = .none
        rpcURLField.autocorrectionType = .no
        rpcURLField.keyboardType = .URL
        rpcURLField.text = UserDefaults.standard.string(forKey: "rpc_url") ?? "https://cloudflare-eth.com"

        addressLabel.numberOfLines = 0
        pubKeyLabel.numberOfLines = 0
        balanceLabel.numberOfLines = 0
        statusLabel.numberOfLines = 0
        statusLabel.textColor = .secondaryLabel

        generateButton.setTitle("Generate/Restore Key", for: .normal)
        deleteButton.setTitle("Delete Key", for: .normal)
        refreshButton.setTitle("Refresh Balance", for: .normal)

        generateButton.addTarget(self, action: #selector(onGenerate), for: .touchUpInside)
        deleteButton.addTarget(self, action: #selector(onDelete), for: .touchUpInside)
        refreshButton.addTarget(self, action: #selector(onRefresh), for: .touchUpInside)

        toField.placeholder = "To address (0x...)"
        toField.borderStyle = .roundedRect
        toField.autocapitalizationType = .none
        toField.autocorrectionType = .no

        amountField.placeholder = "Amount (wei)"
        amountField.borderStyle = .roundedRect
        amountField.keyboardType = .numbersAndPunctuation

        sendButton.setTitle("Sign & Send (ETH)", for: .normal)
        sendButton.addTarget(self, action: #selector(onSend), for: .touchUpInside)

        let stack = UIStackView(arrangedSubviews: [
            rpcURLField,
            generateButton,
            deleteButton,
            addressLabel,
            pubKeyLabel,
            refreshButton,
            balanceLabel,
            UIView(),
            toField,
            amountField,
            sendButton,
            statusLabel
        ])
        stack.axis = .vertical
        stack.spacing = 10
        stack.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(stack)

        NSLayoutConstraint.activate([
            stack.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor, constant: 16),
            stack.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor, constant: -16),
            stack.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
            stack.bottomAnchor.constraint(lessThanOrEqualTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -16)
        ])
    }

    private func loadOrShow() {
        if let priv = KeychainStore.shared.loadPrivateKey(),
           let pub = Secp256k1.publicKey(fromPrivateKey: priv, compressed: false),
           let addr = EthereumWallet.address(fromUncompressedPublicKey: pub) {
            cachedInfo = WalletKeyInfo(address: addr, publicKeyHex: Hex.encode(pub, prefix: true), createdAt: Date())
            addressLabel.text = "Address:\n\(addr)"
            pubKeyLabel.text = "Public Key:\n\(Hex.encode(pub, prefix: true))"
        } else {
            cachedInfo = nil
            addressLabel.text = "Address:\n(none)"
            pubKeyLabel.text = "Public Key:\n(none)"
            balanceLabel.text = "Balance:\n(none)"
        }
    }

    @objc private func onGenerate() {
        let priv = Secp256k1.generatePrivateKey()
        do {
            try KeychainStore.shared.savePrivateKey(priv)
            statusLabel.text = "Saved new private key to Keychain."
            loadOrShow()
        } catch {
            statusLabel.text = "Keychain error: \(error)"
        }
    }

    @objc private func onDelete() {
        KeychainStore.shared.deletePrivateKey()
        statusLabel.text = "Deleted private key."
        loadOrShow()
    }

    @objc private func onRefresh() {
        Task { await refreshBalance() }
    }

    private func rpc() -> EthereumRPC? {
        guard let t = rpcURLField.text, let u = URL(string: t) else { return nil }
        UserDefaults.standard.set(t, forKey: "rpc_url")
        return EthereumRPC(url: u)
    }

    private func currentPrivateKey() -> Data? {
        KeychainStore.shared.loadPrivateKey()
    }

    private func currentAddress() -> String? {
        cachedInfo?.address
    }

    private func showStatus(_ s: String) {
        DispatchQueue.main.async { self.statusLabel.text = s }
    }

    private func setBalanceText(_ s: String) {
        DispatchQueue.main.async { self.balanceLabel.text = "Balance (hex wei):\n\(s)" }
    }

    private func refreshBalance() async {
        guard let rpc = rpc(), let addr = currentAddress() else {
            showStatus("Missing RPC URL or wallet.")
            return
        }
        do {
            showStatus("Fetching balance...")
            let bal = try await rpc.getBalance(address: addr)
            setBalanceText(bal)
            showStatus("Balance updated.")
        } catch {
            showStatus("Balance error: \(error)")
        }
    }

    @objc private func onSend() {
        Task { await signAndSend() }
    }

    private func signAndSend() async {
        guard let rpc = rpc() else { showStatus("Invalid RPC URL."); return }
        guard let priv = currentPrivateKey(), let from = currentAddress() else { showStatus("No wallet key."); return }
        guard let toText = toField.text?.trimmingCharacters(in: .whitespacesAndNewlines), toText.lowercased().hasPrefix("0x") else {
            showStatus("Invalid to address.")
            return
        }
        guard let toDataFull = Hex.decode(toText), toDataFull.count == 20 else { showStatus("To address must be 20 bytes."); return }
        let amountWei = UInt64(amountField.text ?? "") ?? 0

        do {
            showStatus("Preparing transaction...")
            let nonce = try await rpc.getTransactionCount(address: from)
            let gasPrice = try await rpc.gasPrice()
            let gasLimit: UInt64 = 21000
            let chainId: UInt64 = 1

            let tx = EthereumTransaction(
                nonce: nonce,
                gasPrice: gasPrice,
                gasLimit: gasLimit,
                to: toDataFull,
                value: amountWei,
                data: Data(),
                chainId: chainId
            )

            guard let raw = EthereumWallet.signTransaction(tx, privateKey: priv) else {
                showStatus("Signing failed.")
                return
            }

            showStatus("Sending raw transaction...")
            let txHash = try await rpc.sendRawTransaction(raw)
            showStatus("Sent: \(txHash)")
            await refreshBalance()
        } catch {
            showStatus("Send error: \(error)")
        }
    }
}